import{_ as e,o as i,c as a,ae as r}from"./chunks/framework.CRIdhvba.js";const p=JSON.parse('{"title":"后端开发工程师 · 数据库开发工程师学习路线导读","description":"","frontmatter":{"title":"后端开发工程师 · 数据库开发工程师学习路线导读"},"headers":[],"relativePath":"career/backend/db-dev/index.md","filePath":"career/backend/db-dev/index.md"}'),t={name:"career/backend/db-dev/index.md"};function n(o,l,d,s,c,b){return i(),a("div",null,[...l[0]||(l[0]=[r('<h1 id="后端开发工程师-·-数据库开发工程师学习路线导读" tabindex="-1">后端开发工程师 · 数据库开发工程师学习路线导读 <a class="header-anchor" href="#后端开发工程师-·-数据库开发工程师学习路线导读" aria-label="Permalink to &quot;后端开发工程师 · 数据库开发工程师学习路线导读&quot;">​</a></h1><p>数据库开发工程师负责数据库相关系统的 <strong>设计、开发、优化与运维支持</strong>，常见工作包括：</p><ul><li>参与业务系统数据模型设计与评审；</li><li>负责核心表结构、索引与存储过程等实现；</li><li>分析线上慢查询与性能瓶颈，给出优化方案；</li><li>参与数据库分库分表、读写分离、高可用等方案设计；</li><li>与运维/DBA 协作完成容量规划、监控与应急处理。</li></ul><h2 id="学习路线模块一览" tabindex="-1">学习路线模块一览 <a class="header-anchor" href="#学习路线模块一览" aria-label="Permalink to &quot;学习路线模块一览&quot;">​</a></h2><p>点击左侧侧边栏或下方链接，可以进入对应模块的详细教程页面：</p><ol><li><p><strong>数据库基础与概念</strong></p><ul><li>关系模型、表/行/列</li><li>主键、外键、唯一约束</li><li>SQL 基本语法与常见命令</li></ul></li><li><p><strong><a href="/byte-skill/career/backend/db-dev/db-theory/">数据库原理</a></strong></p><ul><li>事务 ACID 特性</li><li>并发控制：锁、MVCC、多版本</li><li>日志系统：重做日志、回滚日志</li></ul></li><li><p><strong><a href="/byte-skill/career/backend/db-dev/storage-engine/">存储引擎</a></strong></p><ul><li>页结构、数据页与索引页</li><li>Buffer Pool 与刷盘策略</li><li>常见存储引擎（如 InnoDB）对上层行为的影响</li></ul></li><li><p><strong><a href="/byte-skill/career/backend/db-dev/sql-advanced/">SQL 与索引优化</a></strong></p><ul><li>执行计划解读</li><li>索引设计原则</li><li>常见慢查询案例分析</li></ul></li><li><p><strong><a href="/byte-skill/career/backend/db-dev/distributed-db/">分布式与高可用数据库</a></strong></p><ul><li>主从复制、读写分离</li><li>分库分表、中间件</li><li>一致性协议与 CAP/Berkeley 视角</li></ul></li><li><p><strong><a href="/byte-skill/career/backend/db-dev/performance-tuning/">性能调优与排障</a></strong></p><ul><li>关键监控指标与常见告警</li><li>锁等待、死锁分析</li><li>热点行/热点表的识别与缓解方案</li></ul></li></ol><h2 id="如何使用本路线" tabindex="-1">如何使用本路线 <a class="header-anchor" href="#如何使用本路线" aria-label="Permalink to &quot;如何使用本路线&quot;">​</a></h2><ul><li>如果你是 <strong>完全新手</strong>：从「数据库基础与概念」开始，先能读懂常见 SQL，再逐步向内部实现推进。</li><li>如果你已经是 <strong>后端工程师</strong>：可以直接从「数据库原理」「存储引擎」开始，帮助你把日常问题与底层原理建立联系。</li><li>如果你在准备 <strong>数据库相关面试</strong>：建议重点关注「SQL 与索引优化」「分布式与高可用」「性能调优与排障」。</li></ul><blockquote><p>建议你在学习过程中，结合真实业务场景或开源项目进行练习，例如：分析某个接口在不同索引设计下的执行计划差异。</p></blockquote>',9)])])}const g=e(t,[["render",n]]);export{p as __pageData,g as default};
